import { assignInlineVars } from '@vanilla-extract/dynamic';
import clsx from 'clsx';
import { isEmpty } from 'lodash-es';
import { CSSProperties, forwardRef } from 'react';

import { SeriesSymbol } from './SeriesSymbol.js';
import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';
import { GAP_BETWEEN_COLUMNS } from '../../constants.js';
import {
  multiLineName,
  relativeValueStyle,
  seriesDescriptionText,
  seriesDescriptionTextMultiLine,
  seriesDescriptionTextMultiLineWrap,
  seriesItem,
  seriesItemMaxWidthVar,
  seriesItemText,
  seriesNameCell,
  seriesNameText,
  seriesValueCell,
  spaceSavedForSymbolVar,
  symbolWrapper,
} from '../../tooltip.sty.js';
import { InternalSeriesItemProps } from '../../types/series.js';

interface SeriesItemContentProps
  extends Omit<InternalSeriesItemProps, 'value'> {
  nameText: string | string[];
  descriptionText?: string;
  fullDescriptionText?: string;
  isDescriptionTruncated?: boolean;
  descriptionShouldUseMultiLineCss?: boolean;
  descriptionMultiLineMode?: 'clamp' | 'wrap';
  displayValueText: string;
  displayRelativeValueText?: string;
  fullValueText: string;
  fullRelativeValueText?: string;
  nameTextStyle: string;
  nameStyle: CSSProperties;
  multiLine: boolean;
  symbolPosition: 'left' | 'right';
  hasChevron?: boolean;
  maxWidth?: number;
}

export const SeriesItemContent = forwardRef<
  HTMLDivElement,
  SeriesItemContentProps
>((props, ref) => {
  const {
    color,
    nameText,
    descriptionText,
    fullDescriptionText,
    isDescriptionTruncated,
    descriptionShouldUseMultiLineCss,
    descriptionMultiLineMode = 'clamp',
    displayValueText,
    displayRelativeValueText,
    fullValueText,
    fullRelativeValueText,
    nameTextStyle,
    nameStyle,
    multiLine = false,
    symbolPosition,
    shape,
    symbol,
    icon,
    iconStyle,
    maxWidth,
    hasChevron = false,
  } = props;
  const isRightPosition = symbolPosition === 'right';
  const hasSymbol =
    (color !== undefined && !isEmpty(color)) ||
    icon !== undefined ||
    symbol !== undefined;
  const renderNameContent = () => {
    if (Array.isArray(nameText) && multiLine) {
      return (
        <ul className={multiLineName}>
          {nameText.map((line) => {
            return (
              <li
                key={`${line}`}
                className={nameTextStyle}
                style={{ ...nameStyle, padding: 0 }}
              >
                <span className={seriesNameText}>{line}</span>
              </li>
            );
          })}
        </ul>
      );
    }

    return (
      <span className={nameTextStyle} style={nameStyle}>
        <span className={seriesNameText}>{nameText}</span>
      </span>
    );
  };

  const renderSymbol = () => {
    return (
      <span className={symbolWrapper({ isRight: isRightPosition })}>
        <SeriesSymbol
          color={color}
          shape={shape}
          symbol={symbol}
          icon={icon}
          iconStyle={iconStyle}
        />
      </span>
    );
  };

  const getDescriptionClassName = () => {
    if (!descriptionShouldUseMultiLineCss) {
      return seriesDescriptionText;
    }
    return descriptionMultiLineMode === 'wrap'
      ? seriesDescriptionTextMultiLineWrap
      : seriesDescriptionTextMultiLine;
  };

  const renderValue = () => {
    const isValueTruncated = displayValueText !== fullValueText;
    const isRelativeValueTruncated =
      displayRelativeValueText !== fullRelativeValueText;

    return (
      <>
        <Tooltip text={fullValueText} disabled={!isValueTruncated}>
          <span className={seriesItemText}>{displayValueText}</span>
        </Tooltip>
        {displayRelativeValueText && (
          <Tooltip
            text={fullRelativeValueText}
            disabled={!isRelativeValueTruncated}
          >
            <span className={clsx(relativeValueStyle, seriesItemText)}>
              {displayRelativeValueText}
            </span>
          </Tooltip>
        )}
      </>
    );
  };

  return (
    <div
      ref={ref}
      className={seriesItem({ symbolPosition, hasChevron })}
      style={assignInlineVars({
        [seriesItemMaxWidthVar]: `${maxWidth}px`,
        [spaceSavedForSymbolVar]: hasSymbol ? '24px' : '6px',
      })}
    >
      <div style={{ gridArea: 'symbol' }}>
        {hasSymbol ? renderSymbol() : null}
      </div>
      <div
        className={seriesNameCell}
        style={{
          gridArea: 'name',
          marginRight: `${GAP_BETWEEN_COLUMNS}px`,
          flexDirection: 'column',
        }}
      >
        {renderNameContent()}
        {descriptionText !== undefined && (
          <Tooltip
            text={fullDescriptionText ?? ''}
            disabled={!isDescriptionTruncated}
          >
            <span
              className={getDescriptionClassName()}
              style={descriptionShouldUseMultiLineCss ? nameStyle : undefined}
            >
              {descriptionText}
            </span>
          </Tooltip>
        )}
      </div>
      <div className={seriesValueCell} style={{ gridArea: 'value' }}>
        {renderValue()}
      </div>
    </div>
  );
});
